module NotebookInstanceStatus =
  struct
    type nonrec t =
      | Pending 
      | InService 
      | Stopping 
      | Stopped 
      | Failed 
      | Deleting 
      | Updating 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | Pending -> "Pending"
      | InService -> "InService"
      | Stopping -> "Stopping"
      | Stopped -> "Stopped"
      | Failed -> "Failed"
      | Deleting -> "Deleting"
      | Updating -> "Updating"
      | Non_static_id s -> s
    let of_string =
      function
      | "Pending" -> Pending
      | "InService" -> InService
      | "Stopping" -> Stopping
      | "Stopped" -> Stopped
      | "Failed" -> Failed
      | "Deleting" -> Deleting
      | "Updating" -> Updating
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string
        (string_of_xml ~kind:"enumeration NotebookInstanceStatus" xml_arg0)
    let of_json j =
      of_string (string_of_json ~kind:"NotebookInstanceStatus" j)
    let to_json = simple_to_json to_value
  end
