  struct
    type nonrec t =
      | Starting 
      | LaunchingMLInstances 
      | PreparingTrainingStack 
      | Downloading 
      | DownloadingTrainingImage 
      | Training 
      | Uploading 
      | Stopping 
      | Stopped 
      | MaxRuntimeExceeded 
      | Completed 
      | Failed 
      | Interrupted 
      | MaxWaitTimeExceeded 
      | Updating 
      | Restarting 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | Starting -> "Starting"
      | LaunchingMLInstances -> "LaunchingMLInstances"
      | PreparingTrainingStack -> "PreparingTrainingStack"
      | Downloading -> "Downloading"
      | DownloadingTrainingImage -> "DownloadingTrainingImage"
      | Training -> "Training"
      | Uploading -> "Uploading"
      | Stopping -> "Stopping"
      | Stopped -> "Stopped"
      | MaxRuntimeExceeded -> "MaxRuntimeExceeded"
      | Completed -> "Completed"
      | Failed -> "Failed"
      | Interrupted -> "Interrupted"
      | MaxWaitTimeExceeded -> "MaxWaitTimeExceeded"
      | Updating -> "Updating"
      | Restarting -> "Restarting"
      | Non_static_id s -> s
    let of_string =
      function
      | "Starting" -> Starting
