 and
  SearchExpressionList:sig
                         type nonrec t = SearchExpression.t list
                         val make : SearchExpression.t list -> t
                         val to_value : t -> Botodata.value
                         val to_query : t -> Client.Query.t
                         val of_xml : Xml.t -> SearchExpression.t list
                         val of_json : Yojson.Safe.t -> t
                         val to_json : t -> Yojson.Safe.t
                         val to_header : t -> string
                       end =
  struct
    type nonrec t = SearchExpression.t list
